import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule } from '@angular/forms';
import { SystemSetting } from '../../core/models';

interface ServiceGroup {
  id: string;
  label: string;
  description: string;
  keys: string[];
}

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrls: ['./admin-settings.component.css'],
})
export class AdminSettingsComponent {
  private fb = inject(FormBuilder);
  savedKey = signal<string | null>(null);

  // Service groups declared in the deployment (postgresql, minio).
  readonly services: ServiceGroup[] = [
    { id: 'postgresql', label: 'PostgreSQL', description: 'Primary application database.', keys: ['DATABASE_URL'] },
    { id: 'minio', label: 'MinIO Object Storage', description: 'S3-compatible storage for product images.', keys: ['MINIO_ENDPOINT', 'MINIO_ACCESS_KEY', 'MINIO_SECRET_KEY'] },
  ];

  // Backend-provided data — kept as a signal per the mockup data contract.
  settings = signal<SystemSetting[]>([
    { key: 'DATABASE_URL', label: 'Connection URL', configured: true, value: 'postgres://••••••@db:5432/store' },
    { key: 'MINIO_ENDPOINT', label: 'Endpoint', configured: false, value: '' },
    { key: 'MINIO_ACCESS_KEY', label: 'Access Key', configured: false, value: '' },
    { key: 'MINIO_SECRET_KEY', label: 'Secret Key', configured: false, value: '' },
  ]);

  form = this.fb.group({});

  constructor() {
    for (const s of this.settings()) {
      this.form.addControl(s.key, this.fb.control(''));
    }
  }

  settingFor(key: string): SystemSetting | undefined {
    return this.settings().find((s) => s.key === key);
  }

  isServiceConfigured(service: ServiceGroup): boolean {
    return service.keys.every((k) => this.settingFor(k)?.configured);
  }

  saveService(service: ServiceGroup): void {
    // Mock PATCH /api/admin/settings — mark provided keys as configured.
    this.settings.update((list) =>
      list.map((s) => {
        if (!service.keys.includes(s.key)) return s;
        const entered = (this.form.get(s.key)?.value as string) ?? '';
        return entered
          ? { ...s, configured: true, value: '••••••••' }
          : s;
      }),
    );
    this.savedKey.set(service.id);
    setTimeout(() => this.savedKey.set(null), 2000);
  }
}
